class Solution:
    def longestSubsequence(self, s: str, k: int) -> int:
        count_ones = s.count('1')
        binary_k = bin(k)[2:]
        n = len(binary_k)
        if count_ones <= n:
            return len(s) - count_ones + count_ones
        for i in range(n):
            if binary_k[i] == '1':
                if s[:len(s)-n+i].count('1') < n-i:
                    return len(s) - (n-i) + (n-i)
        return len(s) - count_ones + n
